#include <bits/stdc++.h>
using namespace std;

int main() {
    int N, M, k;
    cin >> N >> M >> k;
    vector<vector<int>> matrix(N, vector<int>(M));
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < M; ++j) {
