/* 文件头注释：计算两个周期性课间时间的重叠时长 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int K, x, y, p, q;
    cin >> K >> x >> y >> p >> q;

    int total_overlap = 0;

    // 模拟呆唯的课间时间
    int t1_start = x;
    int t1_end = x + y;

    // 模拟阿梓喵的课间时间
    int t2_start = p;
    int t2_end = p + q;

    while (t1_start < K || t2_start < K) {
        // 计算当前课间时间的重叠部分
        int overlap_start = max(t1_start, t2_start);
        int overlap_end = min(t1_end, t2_end);

        if (overlap_start < overlap_end && overlap_start < K) {
            total_overlap += min(overlap_end, K) - overlap_start;
        }

        // 更新下一个课间时间
        if (t1_end < K) {
            t1_start += x + y;
            t1_end += x + y;
        }
        if (t2_end < K) {
            t2_start += p + q;
            t2_end += p + q;
        }
    }

    cout << total_overlap << endl;
    return 0;
}

