    return a / __gcd(a, b) * b;
}

// DFS遍历树，计算每个子树的最小过载周期
void dfs(int u) {
    lcm[u] = a[u];
    for (int v : tree[u]) {
        dfs(v);
        lcm[u] = computeLCM(lcm[u], lcm[v]);  // [FIX] 移除立即取模操作
    }
}

int main() {
    int n, q;
    scanf("%d%d", &n, &q);
    for (int i = 1; i <= n; ++i) {
        scanf("%d", &a[i]);
    }
    for (int i = 2; i <= n; ++i) {
        int parent;
        scanf("%d", &parent);
        tree[parent].push_back(i);
    }

    // 预处理每个子树的最小过载周期
    dfs(1);

    int lastans = 0;
    while (q--) {
        int x;
        scanf("%d", &x);
        int u = (x + lastans) % n + 1;
        lastans = lcm[u] % MOD;  // [FIX] 输出时再取模
        printf("%d\n", lastans);
    }

    return 0;
}

