                prob = 1 - p;
            } else {
                // 上一局是云顶之奕，赢了就换游戏
                prob = q;
            }
            result = prob;
        }
    }

    // 输出结果，保留10位小数
    cout << fixed << setprecision(10) << result << endl;

    return 0;
}

